import{_ as t,o,c as n,ah as r}from"./chunks/framework.C8Zd3T50.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}'),a={name:"introduction.md"};function i(s,e,d,l,c,p){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The internet was originally designed as an open, decentralized system where users controlled their own data and connections. Over time however, Big Tech consolidated power, turning the web into a network of centralized platforms that dictate access, security, and privacy—often at the expense of the users.</p><p><strong>os384 is a new platform designed to reverse this trend.</strong> It enables developers to build sovereign, <a href="/BhoW6b/glossary.html#e2e-encryption-end-to-end-encryption">end-to-end encrypted</a> applications without relying on centralized infrastructure. By combining the ease of Web2 development with the decentralized principles of Web3, os384 eliminates the need for Big Tech middlemen while ensuring <strong>speed, security, and true user ownership of data</strong>.</p><p>Unlike traditional cloud platforms, os384 applications do not require trust in a central authority. Instead, they use cryptographic protocols to enforce data integrity, confidentiality, and access control—<strong>so that only users, not corporations, control their digital lives</strong>.</p><p>With os384, developers can build:</p><ul><li><strong>Private messaging apps</strong> with zero-knowledge encryption</li><li><strong>Collaborative tools</strong> that don’t depend on corporate cloud services</li><li><strong>Personal data vaults</strong> that ensure true <a href="/BhoW6b/glossary.html#sovereignty">data sovereignty</a></li><li><strong>Decentralized applications</strong> that are secure, scalable, and censorship-resistant</li></ul><p>os384 is more than just a development framework—it’s a fundamental rethinking of how apps should work in a world where privacy and digital independence matter more than ever.</p><br><div class="info custom-block"><p class="custom-block-title">Next: Background and Motivation</p><p>In the next section we will expand upon the issues we&#39;re faced with today, both as end-users of software or services, as well as developers of same.</p></div>',9)])])}const g=t(a,[["render",i]]);export{u as __pageData,g as default};
